func TestCopilotCodingAgentDetector_IsGitHubCopilotCodingAgent(t *testing.T) {
	tests := []struct {
		name           string
		setupFunc      func(string) error
		workflowPath   string
		expectedResult bool
	}{
		{
			name: "detects from workflow path copilot-swe-agent.yml",
